fun solve(n: Long): String {
    // Function to convert a number to a given base (hex or base36)
    fun convertToBase(number: Long, base: Int): String {
        if (number == 0L) return "0"
        val digits = mutableListOf<Char>()
        while (number > 0) {
            val remainder = number % base
            if (remainder < 10) {
                digits.add(remainder.toString().toCharArray()[0])
            } else {
                digits.add((remainder - 10 + 'A').toChar())
            }
            number /= base
        }
        return digits.reversed().joinToString("")
    }

    // Calculate n^2 and n^3
    val n2 = n * n
    val n3 = n * n * n

    // Convert to hex and base36
    val hex = convertToBase(n2, 16)
    val base36 = convertToBase(n3, 36)

    // Concatenate and return
    return "$hex$base36"
}
